  // Division must be by power-of-2, but not the minimum signed value.
  Value *X;
  const APInt *DivC;
  if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
      DivC->isNegative())
    return nullptr;

  // Rounding is done by adding -1 if the dividend (X) is negative and has any
  // low bits set. There are two patterns for detecting this condition:
  // Pattern 1: sext (icmp ugt (X & (SMIN | (DivC - 1))), SMIN)
  // Pattern 2: sext (icmp eq (X & (SMIN | (DivC - 1))), (SMIN | (DivC - 1)))
  //   (Pattern 2 is only valid when DivC == 2, since for larger divisors,
  //    it checks that ALL low bits are set, not ANY.)
  const APInt *MaskC, *CmpC;
  ICmpInst::Predicate Pred;
  if (!match(Add.getOperand(1),
             m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
                           m_APInt(CmpC)))))
    return nullptr;

  APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
  APInt CombinedMask = SMin | (*DivC - 1);
  if (*MaskC != CombinedMask)
    return nullptr;

  if (Pred == ICmpInst::ICMP_UGT && *CmpC == SMin) {
    // Pattern 1: ugt with SMIN
  } else if (Pred == ICmpInst::ICMP_EQ && *CmpC == CombinedMask &&
             DivC->exactLogBase2() == 1) {
    // Pattern 2: eq with combined mask (only valid for DivC == 2)
  } else {
    return nullptr;
  }

  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
  return BinaryOperator::CreateAShr(
      X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
}
